import DirectMessageList from "../DirectMessage/DirectMessageList";

import classes from "./SecondarySidebar.module.css";
import SearchBar from "./SearchButton";
import UserIcon from "../DirectMessage/UserIcon";
import DirectMessageItem from "../DirectMessage/DirectMessageItem";

const SecondarySidebar = () => {
  return (
    <div className={classes["secondary-sidebar"]}>
      <SearchBar></SearchBar>
      <DirectMessageList></DirectMessageList>
      <DirectMessageItem>
        <UserIcon></UserIcon>
      </DirectMessageItem>
    </div>
  );
};

export default SecondarySidebar;
